// ─── BASE UI ──────────────────────────────────────────────
const ff="'DM Sans',system-ui,sans-serif", fs="'Playfair Display',Georgia,serif";

function Btn({children,onClick,variant='primary',size='md',disabled=false,style={}}){
  const sz={sm:{padding:'7px 14px',fontSize:13,borderRadius:9},md:{padding:'11px 22px',fontSize:14,borderRadius:10},lg:{padding:'14px 20px',fontSize:15,borderRadius:12,width:'100%',justifyContent:'center'}};
  const va={primary:{background:C.gold,color:C.black},dark:{background:C.black,color:C.gold},secondary:{background:C.beige,color:C.warm},danger:{background:C.redL,color:C.red},ghost:{background:'transparent',color:C.gold,border:`1.5px solid ${C.gold}`},ghostD:{background:'transparent',color:C.warmM,border:`1.5px solid ${C.beigeD}`}};
  return <button onClick={disabled?undefined:onClick} disabled={disabled} style={{fontFamily:ff,fontWeight:600,border:'none',cursor:disabled?'not-allowed':'pointer',display:'inline-flex',alignItems:'center',gap:6,opacity:disabled?.45:1,transition:'opacity .15s',...sz[size],...va[variant],...style}}>{children}</button>;
}

function Inp({label,value,onChange,placeholder,required,type='text',note,style={}}){
  return(
    <div style={{marginBottom:16}}>
      {label&&<div style={{fontSize:11.5,fontWeight:600,color:C.warmM,marginBottom:6,letterSpacing:.4,fontFamily:ff,textTransform:'uppercase'}}>{label}{required&&<span style={{color:C.red}}> *</span>}</div>}
      <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} style={{width:'100%',boxSizing:'border-box',padding:'13px 14px',borderRadius:11,border:`1.5px solid ${C.beigeD}`,background:'#fff',fontFamily:ff,fontSize:16,color:C.warm,outline:'none',...style}}/>
      {note&&<div style={{fontSize:11.5,color:C.warmL,marginTop:4}}>{note}</div>}
    </div>
  );
}

function Sel({label,value,onChange,options,required,placeholder='Select…'}){
  return(
    <div style={{marginBottom:16}}>
      {label&&<div style={{fontSize:11.5,fontWeight:600,color:C.warmM,marginBottom:6,letterSpacing:.4,fontFamily:ff,textTransform:'uppercase'}}>{label}{required&&<span style={{color:C.red}}> *</span>}</div>}
      <div style={{position:'relative'}}>
        <select value={value} onChange={e=>onChange(e.target.value)} style={{width:'100%',padding:'13px 40px 13px 14px',borderRadius:11,border:`1.5px solid ${C.beigeD}`,background:'#fff',fontFamily:ff,fontSize:16,color:value?C.warm:C.warmL,outline:'none',appearance:'none'}}>
          <option value="">{placeholder}</option>
          {options.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}
        </select>
        <div style={{position:'absolute',right:14,top:'50%',transform:'translateY(-50%)',pointerEvents:'none',color:C.warmM,lineHeight:0}}>{Ic.chevR}</div>
      </div>
    </div>
  );
}

function SecHead({title,action}){
  return <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:10,marginTop:4}}><span style={{fontSize:10.5,fontWeight:700,letterSpacing:1.6,textTransform:'uppercase',color:C.warmM,fontFamily:ff}}>{title}</span>{action}</div>;
}

function Chip({active,onClick,children}){
  return <button onClick={onClick} style={{flexShrink:0,padding:'8px 16px',borderRadius:22,fontFamily:ff,fontSize:13,fontWeight:active?600:400,cursor:'pointer',whiteSpace:'nowrap',transition:'all .2s',border:`1.5px solid ${active?C.gold:C.beigeD}`,background:active?C.black:C.beige,color:active?C.gold:C.warmM}}>{children}</button>;
}

function Tag({children,color='amber'}){
  const cols={red:{bg:C.redL,fg:C.red},amber:{bg:C.amberL,fg:C.amber},green:{bg:C.greenL,fg:C.green},gold:{bg:C.goldP,fg:C.warm}};
  const {bg,fg}=cols[color]||cols.amber;
  return <span style={{fontSize:10.5,fontWeight:700,letterSpacing:.4,padding:'2px 8px',borderRadius:6,background:bg,color:fg,fontFamily:ff}}>{children}</span>;
}

function ErrBox({msg}){if(!msg)return null;return <div style={{color:C.red,fontSize:13,marginBottom:14,background:C.redL,padding:'10px 14px',borderRadius:10,fontFamily:ff,fontWeight:500}}>{msg}</div>;}

// ─── BOTTOM SHEET ─────────────────────────────────────────
function Sheet({title,onClose,children}){
  return(
    <div style={{position:'fixed',inset:0,zIndex:300,display:'flex',flexDirection:'column',justifyContent:'flex-end'}}>
      <div onClick={onClose} style={{flex:1,background:'rgba(10,9,8,.65)',backdropFilter:'blur(3px)'}}/>
      <div style={{background:C.cream,borderRadius:'22px 22px 0 0',maxHeight:'90vh',overflowY:'auto',paddingBottom:'max(env(safe-area-inset-bottom),20px)',boxShadow:'0 -4px 40px rgba(0,0,0,.2)'}}>
        <div style={{position:'sticky',top:0,background:C.cream,zIndex:2,borderRadius:'22px 22px 0 0'}}>
          <div style={{display:'flex',justifyContent:'center',padding:'12px 0 6px'}}><div style={{width:40,height:4,background:C.beigeD,borderRadius:2}}/></div>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'0 20px 14px',borderBottom:`1px solid ${C.beige}`}}>
            <span style={{fontFamily:fs,fontSize:20,fontWeight:700,color:C.warm}}>{title}</span>
            <button onClick={onClose} style={{background:C.beige,border:'none',borderRadius:9,padding:'7px',cursor:'pointer',display:'flex',color:C.warmM,lineHeight:0}}>{Ic.close}</button>
          </div>
        </div>
        <div style={{padding:'18px 20px 8px'}}>{children}</div>
      </div>
    </div>
  );
}

// ─── MODALS ───────────────────────────────────────────────
function AdjustModal({stockId,data,refresh,onClose,user}){
  const [apiErr,setApiErr]=useState('');
  const showErr=msg=>{setApiErr(msg);setTimeout(()=>setApiErr(''),4000);};

  const s=data.stock.find(x=>x.id===stockId);
  const it=data.items.find(i=>i.id===s?.iid);
  const lc=data.locations.find(l=>l.id===s?.lid);
  const [qty,setQty]=useState(s?.qty??0);
  const [editing,setEditing]=useState(false);
  const [val,setVal]=useState('');
  if(!s||!it)return null;
  const isLow=qty<=it.lowAt;
  const apply=async q=>{if(q<0)return;setQty(q);try{await api.adjust(stockId,q,{userId:user?.id,userName:user?.name});await refresh();}catch(e){showErr(e.message);}};
  const commit=()=>{const n=parseInt(val);if(!isNaN(n)&&n>=0)apply(n);setEditing(false);};
  return(
    <Sheet title="Adjust Quantity" onClose={onClose}>
      <div style={{textAlign:'center',marginBottom:24}}>
        <div style={{fontWeight:700,fontSize:16,color:C.warm,fontFamily:ff}}>{it.name}</div>
        <div style={{color:C.warmM,fontSize:13,marginTop:3}}>{lc?.name} · per {it.uom}</div>
        {isLow&&<div style={{marginTop:10,background:C.redL,color:C.red,borderRadius:8,padding:'6px 14px',display:'inline-flex',alignItems:'center',gap:5,fontSize:12,fontWeight:600}}>{Ic.warn} Low stock — threshold: {it.lowAt}</div>}
      </div>
      <div style={{display:'flex',alignItems:'center',justifyContent:'center',gap:18,marginBottom:28}}>
        <button onClick={()=>apply(qty-1)} disabled={qty<=0} style={{width:64,height:64,borderRadius:'50%',background:qty<=0?C.beige:C.black,color:qty<=0?C.beigeD:C.gold,border:'none',cursor:qty<=0?'not-allowed':'pointer',fontSize:30,lineHeight:1,display:'flex',alignItems:'center',justifyContent:'center'}}>−</button>
        {editing?(
          <input autoFocus type="number" inputMode="numeric" value={val} onChange={e=>setVal(e.target.value)} onBlur={commit} onKeyDown={e=>e.key==='Enter'&&commit()} style={{width:110,fontSize:44,fontWeight:700,textAlign:'center',border:`2.5px solid ${C.gold}`,borderRadius:14,background:'#fff',fontFamily:fs,color:C.warm,padding:'8px 0',outline:'none'}}/>
        ):(
          <div onClick={()=>{setVal(String(qty));setEditing(true);}} style={{cursor:'pointer',textAlign:'center',minWidth:100}}>
            <div style={{fontSize:60,fontWeight:700,fontFamily:fs,color:isLow?C.red:C.warm,lineHeight:1}}>{qty}</div>
            <div style={{fontSize:11,color:C.warmL,marginTop:2,fontFamily:ff}}>tap to set exact</div>
          </div>
        )}
        <button onClick={()=>apply(qty+1)} style={{width:64,height:64,borderRadius:'50%',background:C.gold,color:C.black,border:'none',cursor:'pointer',fontSize:30,lineHeight:1,display:'flex',alignItems:'center',justifyContent:'center'}}>+</button>
      </div>
      {apiErr&&<ErrBox msg={apiErr}/>}
      <Btn onClick={onClose} variant="dark" size="lg">Done</Btn>
    </Sheet>
  );
}

function TransferModal({prefillItemId,prefillFromId,data,refresh,onClose,user}){
  const [itemId,setItemId]=useState(prefillItemId||'');
  const [fromId,setFromId]=useState(prefillFromId||'');
  const [toId,setToId]=useState('');
  const [qty,setQty]=useState('1');
  const [err,setErr]=useState('');
  const [done,setDone]=useState(false);
  const fromS=data.stock.find(s=>s.iid===itemId&&s.lid===fromId);
  const avail=fromS?.qty??0;
  const toOpts=data.locations.filter(l=>l.id!==fromId).map(l=>({value:l.id,label:l.name}));
  const go=async()=>{
    setErr('');
    const n=parseInt(qty);
    if(!itemId||!fromId||!toId){setErr('Fill all fields');return;}
    if(!n||n<=0){setErr('Quantity must be at least 1');return;}
    if(n>avail){setErr(`Only ${avail} available at source`);return;}
    if(fromId===toId){setErr('Source and destination must differ');return;}
    let ns=[...data.stock];
    const fi=ns.findIndex(s=>s.iid===itemId&&s.lid===fromId);
    ns[fi]={...ns[fi],qty:ns[fi].qty-n};
    const ti=ns.findIndex(s=>s.iid===itemId&&s.lid===toId);
    if(ti>=0)ns[ti]={...ns[ti],qty:ns[ti].qty+n};
    // handled server-side
    try{await api.transfer(itemId,fromId,toId,n,{userId:user?.id,userName:user?.name});await refresh();setDone(true);}catch(e){setErr(e.message);}
  };
  if(done){
    const it=data.items.find(i=>i.id===itemId);
    const toLoc=data.locations.find(l=>l.id===toId);
    return(
      <Sheet title="Transfer Complete" onClose={onClose}>
        <div style={{textAlign:'center',padding:'16px 0 12px'}}>
          <div style={{width:64,height:64,background:C.greenL,borderRadius:'50%',display:'flex',alignItems:'center',justifyContent:'center',margin:'0 auto 16px',color:C.green,fontSize:26,lineHeight:0}}>{Ic.check}</div>
          <div style={{fontWeight:700,fontSize:17,color:C.green,fontFamily:ff}}>Transfer Successful</div>
          <div style={{color:C.warmM,fontSize:14,marginTop:8,lineHeight:1.6}}>Moved <strong>{qty} {it?.uom}</strong> of <strong>{it?.name}</strong><br/>to <strong>{toLoc?.name}</strong></div>
          <div style={{marginTop:22}}><Btn onClick={onClose} variant="dark" size="lg">Done</Btn></div>
        </div>
      </Sheet>
    );
  }
  return(
    <Sheet title="Transfer Stock" onClose={onClose}>
      <Sel label="Item" value={itemId} onChange={setItemId} required options={data.items.map(i=>({value:i.id,label:i.name}))}/>
      <Sel label="From Location" value={fromId} onChange={v=>{setFromId(v);setToId('');}} required options={data.locations.map(l=>({value:l.id,label:l.name}))}/>
      {fromId&&itemId&&<div style={{fontSize:13,fontWeight:500,padding:'7px 12px',borderRadius:9,marginBottom:12,marginTop:-6,background:avail<1?C.redL:C.greenL,color:avail<1?C.red:C.green}}>Available at source: {avail} {data.items.find(i=>i.id===itemId)?.uom}</div>}
      <Sel label="To Location" value={toId} onChange={setToId} required options={toOpts}/>
      <Inp label="Quantity" value={qty} onChange={setQty} type="number" required/>
      <ErrBox msg={err}/>
      <Btn onClick={go} variant="dark" size="lg"><span style={{lineHeight:0}}>{Ic.trans}</span> Transfer</Btn>
    </Sheet>
  );
}

const UOM_OPTS=['Box','Case','Bag','Bottle','Can','Kg','L','Each','Dozen','Pack','Jar','Sack'];
function AddEditItemModal({editItem,data,refresh,onClose}){
  const [name,setName]=useState(editItem?.name||prefill?.name||'');
  const [uom,setUom]=useState(editItem?.uom||prefill?.uom||'');
  const [desc,setDesc]=useState(editItem?.desc||prefill?.desc||'');
  const [supplier,setSupplier]=useState(editItem?.supplier||prefill?.supplier||'');
  const [lowAt,setLowAt]=useState(String(editItem?.lowAt??prefill?.lowAt??2));
  const [err,setErr]=useState('');
  const save=async()=>{
    if(!name.trim()){setErr('Item name is required');return;}
    if(!uom.trim()){setErr('Unit of measure is required');return;}
    const p={name:name.trim(),uom:uom.trim(),desc:desc.trim(),supplier:supplier.trim(),lowAt:parseInt(lowAt)||2};
    try{if(editItem)await api.updateItem(editItem.id,p);else await api.createItem(p);await refresh();onClose();}catch(e){setErr(e.message);}
  };
  return(
    <Sheet title={editItem?'Edit Item':'New Item'} onClose={onClose}>
      <Inp label="Item Name" value={name} onChange={setName} placeholder="e.g. Oat Milk" required/>
      <div style={{marginBottom:16}}>
        <div style={{fontSize:11.5,fontWeight:600,color:C.warmM,marginBottom:6,letterSpacing:.4,textTransform:'uppercase',fontFamily:ff}}>Unit of Measure <span style={{color:C.red}}>*</span></div>
        <input value={uom} onChange={e=>setUom(e.target.value)} placeholder="e.g. Box" style={{width:'100%',boxSizing:'border-box',padding:'13px 14px',borderRadius:11,border:`1.5px solid ${C.beigeD}`,background:'#fff',fontFamily:ff,fontSize:16,color:C.warm,outline:'none',marginBottom:8}}/>
        <div style={{display:'flex',flexWrap:'wrap',gap:7}}>
          {UOM_OPTS.map(u=><button key={u} onClick={()=>setUom(u)} style={{padding:'5px 13px',borderRadius:22,fontFamily:ff,fontSize:12.5,cursor:'pointer',border:`1.5px solid ${uom===u?C.gold:C.beigeD}`,background:uom===u?C.goldP:C.beige,color:uom===u?C.warm:C.warmM,fontWeight:uom===u?600:400}}>{u}</button>)}
        </div>
      </div>
      <Inp label="Description" value={desc} onChange={setDesc} placeholder="Optional"/>
      {user?.role==='admin'&&<Inp label="Supplier" value={supplier} onChange={setSupplier} placeholder="Optional"/>}
      <Inp label="Low Stock Alert Threshold" value={lowAt} onChange={setLowAt} type="number" note="Flag item when quantity is at or below this number"/>
      <ErrBox msg={err}/>
      <Btn onClick={save} variant="dark" size="lg">{editItem?'Save Changes':'Add to Catalog'}</Btn>
    </Sheet>
  );
}

function AddLocationModal({data,refresh,onClose}){
  const [name,setName]=useState('');
  const [err,setErr]=useState('');
  const save=async()=>{
    if(!name.trim()){setErr('Location name is required');return;}
    try{await api.createLocation(name.trim());await refresh();onClose();}catch(e){setErr(e.message);}
  };
  return(
    <Sheet title="Add Location" onClose={onClose}>
      <Inp label="Location Name" value={name} onChange={setName} placeholder="e.g. Downtown Branch" required/>
      <ErrBox msg={err}/>
      <Btn onClick={save} variant="dark" size="lg">Add Location</Btn>
    </Sheet>
  );
}

function AddStockModal({locationId,data,refresh,onClose}){
  const loc=data.locations.find(l=>l.id===locationId);
  const [itemId,setItemId]=useState('');
  const [qty,setQty]=useState('0');
  const [err,setErr]=useState('');
  const existing=data.stock.find(s=>s.iid===itemId&&s.lid===locationId);
  const save=async()=>{
    if(!itemId){setErr('Select an item');return;}
    const q=parseInt(qty)||0;
    try{await api.addStock(itemId,locationId,q);await refresh();onClose();}catch(e){setErr(e.message);}
  };
  if(data.items.length===0)return <Sheet title="Add Item" onClose={onClose}><div style={{textAlign:'center',padding:'20px 0',color:C.warmM,fontFamily:ff}}>No items in catalog yet. Go to Catalog to add items first.</div></Sheet>;
  return(
    <Sheet title={`Add to ${loc?.name}`} onClose={onClose}>
      <Sel label="Select Item" value={itemId} onChange={setItemId} required options={data.items.map(i=>({value:i.id,label:`${i.name} (${i.uom})`}))}/>
      {existing&&<div style={{fontSize:13,color:C.amber,background:C.amberL,padding:'7px 12px',borderRadius:9,marginBottom:14,marginTop:-6}}>Already tracked here ({existing.qty} {data.items.find(i=>i.id===itemId)?.uom}). This will add to existing quantity.</div>}
      <Inp label="Initial Quantity" value={qty} onChange={setQty} type="number"/>
      <ErrBox msg={err}/>
      <Btn onClick={save} variant="dark" size="lg">Add to Location</Btn>
    </Sheet>
  );
}

function ConfirmModal({title,message,onConfirm,onClose}){
  return(
    <Sheet title={title} onClose={onClose}>
      <div style={{color:C.warmM,fontSize:14.5,lineHeight:1.5,marginBottom:22,fontFamily:ff}}>{message}</div>
      <div style={{display:'flex',gap:10}}>
        <Btn onClick={onClose} variant="secondary" size="lg" style={{flex:1}}>Cancel</Btn>
        <Btn onClick={()=>{onConfirm();onClose();}} variant="danger" size="lg" style={{flex:1}}>Delete</Btn>
      </div>
    </Sheet>
  );
}

// ─── VIEWS ────────────────────────────────────────────────
function DashboardView({data,openModal}){
  const low=data.stock.filter(s=>{const it=data.items.find(i=>i.id===s.iid);return it&&s.qty<=it.lowAt;});
  const recentLog=(data.log||[]).slice(0,5);
  return(
    <div style={{padding:'18px 16px'}}>
      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:8,marginBottom:20}}>
        {[{v:data.locations.length,l:'Locations'},{v:data.items.length,l:'Items'},{v:data.stock.reduce((a,s)=>a+s.qty,0),l:'Total Units'}].map(({v,l})=>(
          <div key={l} style={{background:C.black,borderRadius:14,padding:'16px 8px',textAlign:'center',boxShadow:'0 2px 14px rgba(0,0,0,.2)'}}>
            <div style={{fontFamily:fs,fontSize:28,fontWeight:700,color:C.gold,lineHeight:1}}>{v}</div>
            <div style={{fontSize:9.5,color:C.warmL,marginTop:4,textTransform:'uppercase',letterSpacing:.8,fontFamily:ff}}>{l}</div>
          </div>
        ))}
      </div>
      {low.length>0?(
        <>
          <SecHead title={`⚠ Low Stock (${low.length})`}/>
          {low.map(s=>{
            const it=data.items.find(i=>i.id===s.iid);
            const lc=data.locations.find(l=>l.id===s.lid);
            return(
              <div key={s.id} onClick={()=>openModal({type:'adjust',stockId:s.id})} style={{background:'#fff',borderRadius:14,padding:'13px 16px',marginBottom:8,display:'flex',justifyContent:'space-between',alignItems:'center',borderLeft:`3.5px solid ${C.red}`,cursor:'pointer',boxShadow:'0 1px 6px rgba(0,0,0,.06)'}}>
                <div style={{minWidth:0}}>
                  <div style={{fontWeight:600,fontSize:14,fontFamily:ff}}>{it?.name}</div>
                  <div style={{color:C.warmM,fontSize:12,marginTop:2}}>{lc?.name}</div>
                </div>
                <div style={{display:'flex',alignItems:'center',gap:8,flexShrink:0}}>
                  <div style={{background:C.redL,color:C.red,padding:'4px 14px',borderRadius:22,fontWeight:700,fontSize:17,fontFamily:fs}}>{s.qty}<span style={{fontSize:11,fontWeight:400,fontFamily:ff}}> {it?.uom}</span></div>
                  <div style={{lineHeight:0,color:C.warmL}}>{Ic.chevR}</div>
                </div>
              </div>
            );
          })}
        </>
      ):(
        <div style={{background:'#fff',borderRadius:14,padding:'22px',textAlign:'center',marginBottom:20,boxShadow:'0 1px 6px rgba(0,0,0,.06)'}}>
          <div style={{fontSize:30,marginBottom:8}}>☕</div>
          <div style={{color:C.green,fontWeight:600,fontFamily:ff,fontSize:15}}>All stocked up</div>
          <div style={{color:C.warmL,fontSize:13,marginTop:4,fontFamily:ff}}>Every item is above its reorder threshold</div>
        </div>
      )}
      <div style={{marginTop:low.length?16:0}}>
        <SecHead title="Locations Overview" action={<Btn variant="secondary" size="sm" onClick={()=>openModal({type:'add-location'})}>{Ic.plus} Add</Btn>}/>
        {data.locations.map(loc=>{
          const ls=data.stock.filter(s=>s.lid===loc.id);
          const ll=ls.filter(s=>{const it=data.items.find(i=>i.id===s.iid);return it&&s.qty<=it.lowAt;});
          return(
            <div key={loc.id} style={{background:'#fff',borderRadius:14,padding:'13px 16px',marginBottom:8,display:'flex',justifyContent:'space-between',alignItems:'center',boxShadow:'0 1px 6px rgba(0,0,0,.05)'}}>
              <div>
                <div style={{fontWeight:600,fontSize:14,fontFamily:ff}}>{loc.name}</div>
                <div style={{color:C.warmM,fontSize:12,marginTop:2}}>{ls.length} items · {ls.reduce((a,s)=>a+s.qty,0)} units</div>
              </div>
              {ll.length>0&&<Tag color="red">{ll.length} low</Tag>}
            </div>
          );
        })}
      </div>
      {/* Recent Activity */}
      <div style={{marginTop:20}}>
        <SecHead title="Recent Activity" action={recentLog.length>0&&<button onClick={()=>openModal({type:'log'})} style={{fontSize:12.5,fontWeight:600,color:C.gold,background:'none',border:'none',cursor:'pointer',fontFamily:ff,padding:0}}>View all →</button>}/>
        {recentLog.length===0?(
          <div style={{background:'#fff',borderRadius:14,padding:'18px',textAlign:'center',boxShadow:'0 1px 6px rgba(0,0,0,.05)'}}>
            <div style={{color:C.warmL,fontSize:13,fontFamily:ff}}>No activity yet — adjustments and transfers will appear here</div>
          </div>
        ):recentLog.map(e=><LogEntry key={e.id} e={e} data={data}/>)}
      </div>
    </div>
  );
}

function InventoryView({data,refresh,openModal,user}){
  const [locId,setLocId]=useState(data.locations[0]?.id||'');
  const [search,setSearch]=useState('');
  const [selectedId,setSelectedId]=useState(null);
  const [countMode,setCountMode]=useState(false);
  const [counts,setCounts]=useState({});
  const [saved,setSaved]=useState(null); // {n} after save

  const locStock=data.stock.filter(s=>s.lid===locId);
  const allItems=locStock.map(s=>({s,it:data.items.find(i=>i.id===s.iid)})).filter(x=>x.it);
  const visible=allItems.filter(({it})=>it.name.toLowerCase().includes(search.toLowerCase()));
  const quickAdj=async(s,delta)=>{const nq=s.qty+delta;if(nq<0)return;try{await api.adjust(s.id,nq,{userId:user?.id,userName:user?.name});await refresh();}catch{}};
  const hasStock=locStock.some(s=>s.qty>0);

  const enterCount=()=>{
    const init={};
    locStock.forEach(s=>{init[s.id]=String(s.qty);});
    setCounts(init);
    setCountMode(true);
    setSelectedId(null);
    setSaved(null);
  };
  const cancelCount=()=>{setCountMode(false);setCounts({});setSaved(null);};

  const changedEntries=countMode?locStock.filter(s=>{
    const n=parseInt(counts[s.id]);
    return !isNaN(n)&&n>=0&&n!==s.qty;
  }):[];

  const saveCount=async ()=>{
    if(changedEntries.length===0){cancelCount();return;}
    let d={...data,stock:[...data.stock]};
    try{
      const changes=changedEntries.map(s=>({stockId:s.id,qty:parseInt(counts[s.id])}));
      await api.batchAdjust(changes,{userId:user?.id,userName:user?.name});
      await refresh();
      setSaved({n:changedEntries.length});
    }catch(e){setSaved(null);}
    setCountMode(false);
    setCounts({});
    setTimeout(()=>setSaved(null),3000);
  };

  return(
    <div style={{paddingBottom:16}}>
      {/* Location chips — locked during count */}
      <div style={{padding:'12px 16px 10px',overflowX:'auto',display:'flex',gap:8,borderBottom:`1px solid ${C.beige}`,scrollbarWidth:'none',WebkitOverflowScrolling:'touch'}}>
        {data.locations.map(l=>(
          <Chip key={l.id} active={locId===l.id} onClick={()=>{if(countMode)return;setLocId(l.id);setSearch('');setSelectedId(null);}}>{l.name}</Chip>
        ))}
      </div>

      {/* Toolbar */}
      {countMode?(
        <div style={{padding:'10px 16px 6px',background:C.black,display:'flex',alignItems:'center',justifyContent:'space-between',gap:8}}>
          <div style={{fontFamily:ff,fontSize:13,color:C.gold,fontWeight:600}}>
            Stock Count · {data.locations.find(l=>l.id===locId)?.name}
          </div>
          <div style={{fontSize:12,color:changedEntries.length>0?C.gold:C.warmL,fontFamily:ff,fontWeight:500}}>
            {changedEntries.length} change{changedEntries.length!==1?'s':''}
          </div>
        </div>
      ):(
        <div style={{padding:'10px 16px 4px',display:'flex',gap:8,alignItems:'center'}}>
          <div style={{flex:1,position:'relative'}}>
            <div style={{position:'absolute',left:11,top:'50%',transform:'translateY(-50%)',color:C.warmL,pointerEvents:'none',lineHeight:0}}>{Ic.search}</div>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search items…" style={{width:'100%',boxSizing:'border-box',padding:'9px 12px 9px 34px',borderRadius:10,border:`1.5px solid ${C.beigeD}`,background:'#fff',fontFamily:ff,fontSize:15,color:C.warm,outline:'none'}}/>
          </div>
          <Btn variant="secondary" size="sm" onClick={()=>openModal({type:'add-stock',locationId:locId})} style={{flexShrink:0}}>{Ic.plus} Add</Btn>
          {locStock.length>0&&<Btn variant="dark" size="sm" onClick={enterCount} style={{flexShrink:0}}>
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2"><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h11"/></svg>
            Count
          </Btn>}
        </div>
      )}

      {/* Saved confirmation toast */}
      {saved&&(
        <div style={{margin:'8px 16px 0',padding:'10px 14px',background:C.greenL,borderRadius:10,display:'flex',alignItems:'center',gap:8,fontFamily:ff,fontSize:13,color:C.green,fontWeight:600}}>
          {Ic.check} {saved.n} item{saved.n!==1?'s':''} updated
        </div>
      )}

      {/* Hint */}
      {!countMode&&visible.length>0&&!selectedId&&(
        <div style={{textAlign:'center',fontSize:12,color:C.warmL,fontFamily:ff,padding:'2px 0 6px',letterSpacing:.2}}>Tap a row to adjust quantity</div>
      )}
      {countMode&&(
        <div style={{textAlign:'center',fontSize:12,color:C.warmL,fontFamily:ff,padding:'6px 0 4px',letterSpacing:.2}}>Enter actual quantities on hand</div>
      )}

      {/* Item list */}
      <div style={{padding:'2px 16px 80px'}}>
        {visible.length===0?(
          <div style={{textAlign:'center',padding:'50px 0',color:C.warmL,fontFamily:ff}}>
            <div style={{fontSize:36,marginBottom:10}}>☕</div>
            <div style={{fontWeight:600,fontSize:15}}>{search?'Nothing in the grind':'No stock here yet'}</div>
            <div style={{fontSize:13,marginTop:5}}>{search?'Try a different search':'Tap Add to start tracking stock at this location'}</div>
          </div>
        ):visible.map(({s,it})=>{
          const isLow=s.qty<=it.lowAt;
          const isSel=selectedId===s.id;
          const countVal=counts[s.id]??String(s.qty);
          const newQty=parseInt(countVal);
          const delta=!isNaN(newQty)?newQty-s.qty:0;
          const changed=!isNaN(newQty)&&newQty!==s.qty;

          if(countMode){
            return(
              <div key={s.id} style={{background:'#fff',borderRadius:14,padding:'12px 14px',marginBottom:8,display:'flex',alignItems:'center',gap:12,boxShadow:'0 1px 6px rgba(0,0,0,.05)',borderLeft:`3px solid ${changed?(delta>0?C.green:C.red):'transparent'}`,transition:'border-color .15s'}}>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontWeight:600,fontSize:14,fontFamily:ff,color:C.warm,display:'flex',alignItems:'center',gap:6,flexWrap:'wrap'}}>
                    {it.name}{isLow&&<Tag color="red">LOW</Tag>}
                  </div>
                  <div style={{fontSize:11.5,color:C.warmL,marginTop:2,fontFamily:ff}}>
                    was <span style={{fontWeight:600,color:C.warmM}}>{s.qty}</span> {it.uom}
                    {changed&&<span style={{marginLeft:6,fontWeight:700,color:delta>0?C.green:C.red}}>{delta>0?'+':''}{delta}</span>}
                  </div>
                </div>
                <input
                  type="number"
                  inputMode="numeric"
                  value={countVal}
                  onChange={e=>setCounts(c=>({...c,[s.id]:e.target.value}))}
                  onClick={e=>e.target.select()}
                  style={{width:72,padding:'8px 10px',fontSize:20,fontWeight:700,fontFamily:fs,textAlign:'center',borderRadius:10,border:`2px solid ${changed?(delta>0?C.green:C.red):C.beigeD}`,background:changed?(delta>0?C.greenL:C.redL):'#fff',color:changed?(delta>0?C.green:C.red):C.warm,outline:'none',flexShrink:0,transition:'all .15s'}}
                />
              </div>
            );
          }

          return(
            <div key={s.id}
              onClick={()=>setSelectedId(isSel?null:s.id)}
              style={{background:isSel?C.black:'#fff',borderRadius:14,padding:'12px 14px',marginBottom:8,display:'flex',alignItems:'center',gap:8,boxShadow:isSel?'0 3px 16px rgba(0,0,0,.22)':'0 1px 6px rgba(0,0,0,.05)',borderLeft:`3px solid ${isLow?C.red:isSel?C.gold:'transparent'}`,cursor:'pointer',transition:'all .18s'}}
            >
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontWeight:600,fontSize:14,fontFamily:ff,display:'flex',alignItems:'center',gap:6,flexWrap:'wrap',color:isSel?C.cream:C.warm}}>{it.name}{isLow&&<Tag color="red">LOW</Tag>}</div>
                {it.desc&&<div style={{fontSize:11.5,marginTop:2,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap',fontFamily:ff,color:C.warmL}}>{it.desc}</div>}
                {!isSel&&it.supplier&&user?.role==='admin'&&<div style={{fontSize:11,color:C.warmL,marginTop:1,fontFamily:ff}}>{it.supplier}</div>}
                {isSel&&<div style={{fontSize:11,color:C.warmL,marginTop:3,fontFamily:ff}}>Tap row again to deselect</div>}
              </div>
              <div style={{display:'flex',alignItems:'center',gap:5,flexShrink:0}} onClick={e=>e.stopPropagation()}>
                {isSel?(
                  <>
                    <button onClick={()=>quickAdj(s,-1)} disabled={s.qty<=0} style={{width:38,height:38,borderRadius:'50%',border:'none',cursor:s.qty<=0?'not-allowed':'pointer',background:s.qty<=0?'#333':C.gold,color:s.qty<=0?'#555':C.black,fontSize:24,lineHeight:1,display:'flex',alignItems:'center',justifyContent:'center',transition:'all .15s'}}>−</button>
                    <div onClick={()=>openModal({type:'adjust',stockId:s.id})} style={{cursor:'pointer',textAlign:'center',minWidth:46}}>
                      <div style={{fontSize:22,fontWeight:700,fontFamily:fs,color:isLow?C.red:C.gold,lineHeight:1}}>{s.qty}</div>
                      <div style={{fontSize:9.5,color:C.warmL,fontFamily:ff,lineHeight:1.2}}>{it.uom}</div>
                    </div>
                    <button onClick={()=>quickAdj(s,1)} style={{width:38,height:38,borderRadius:'50%',border:'none',cursor:'pointer',background:C.gold,color:C.black,fontSize:24,lineHeight:1,display:'flex',alignItems:'center',justifyContent:'center'}}>+</button>
                    <button onClick={e=>{e.stopPropagation();openModal({type:'transfer',prefillItemId:it.id,prefillFromId:locId});}} title="Transfer this item" style={{height:34,padding:'0 10px',borderRadius:10,border:`1.5px solid ${C.warmM}`,background:'transparent',color:C.warmL,display:'flex',alignItems:'center',gap:4,cursor:'pointer',fontFamily:ff,fontSize:12,fontWeight:600,lineHeight:1,flexShrink:0}}>
                      <span style={{lineHeight:0}}>{Ic.trans}</span>
                      <span>→</span>
                    </button>
                    <button onClick={e=>{e.stopPropagation();openModal({type:'consume',stockId:s.id});}} title="Record consumption" style={{height:34,padding:'0 10px',borderRadius:10,border:`1.5px solid ${C.amber}`,background:C.amberL,color:C.amber,cursor:'pointer',fontFamily:ff,fontSize:12,fontWeight:700,lineHeight:1,flexShrink:0}}>
                      ☕ Took
                    </button>
                  </>
                ):(
                  <div style={{textAlign:'center',minWidth:46}}>
                    <div style={{fontSize:22,fontWeight:700,fontFamily:fs,color:isLow?C.red:C.warm,lineHeight:1}}>{s.qty}</div>
                    <div style={{fontSize:9.5,color:C.warmL,fontFamily:ff,lineHeight:1.2}}>{it.uom}</div>
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* FAB — swaps between Transfer and Count actions */}
      <div style={{position:'fixed',bottom:82,left:'50%',transform:'translateX(-50%)',width:'100%',maxWidth:480,pointerEvents:'none',display:'flex',justifyContent:'center',gap:10,zIndex:90}}>
        {countMode?(
          <>
            <button onClick={cancelCount} style={{pointerEvents:'auto',padding:'13px 22px',borderRadius:50,background:'#fff',color:C.warmM,border:`2px solid ${C.beigeD}`,fontFamily:ff,fontSize:14,fontWeight:600,cursor:'pointer',boxShadow:'0 4px 14px rgba(0,0,0,.12)'}}>
              Cancel
            </button>
            <button onClick={saveCount} style={{pointerEvents:'auto',display:'flex',alignItems:'center',gap:8,padding:'13px 26px',borderRadius:50,background:changedEntries.length>0?C.black:'#999',color:changedEntries.length>0?C.gold:'#ccc',border:`2px solid ${changedEntries.length>0?C.gold:'#bbb'}`,boxShadow:changedEntries.length>0?'0 4px 20px rgba(0,0,0,.35)':'none',fontFamily:ff,fontSize:15,fontWeight:700,cursor:'pointer',letterSpacing:.2,transition:'all .2s'}}>
              {Ic.check} Save{changedEntries.length>0?` (${changedEntries.length})`:''}
            </button>
          </>
        ):(
          <button
            onClick={()=>openModal({type:'transfer',prefillFromId:locId})}
            disabled={!hasStock}
            style={{pointerEvents:'auto',display:'flex',alignItems:'center',gap:9,padding:'13px 26px',borderRadius:50,background:hasStock?C.black:'#999',color:hasStock?C.gold:'#ccc',border:`2px solid ${hasStock?C.gold:'#bbb'}`,boxShadow:hasStock?'0 4px 20px rgba(0,0,0,.35)':'none',fontFamily:ff,fontSize:15,fontWeight:700,cursor:hasStock?'pointer':'not-allowed',letterSpacing:.2,transition:'all .2s'}}
          >
            <span style={{lineHeight:0}}>{Ic.trans}</span>
            Transfer from here
          </button>
        )}
      </div>
    </div>
  );
}

function CatalogView({data,refresh,openModal,user}){
  const [search,setSearch]=useState('');
  const filtered=data.items.filter(i=>i.name.toLowerCase().includes(search.toLowerCase())||(i.supplier&&i.supplier.toLowerCase().includes(search.toLowerCase())));
  const deleteItem=async id=>{try{await api.deleteItem(id);await refresh();}catch(e){alert(e.message);}};
  return(
    <div style={{padding:'14px 16px'}}>
      <div style={{display:'flex',gap:8,marginBottom:14,alignItems:'center'}}>
        <div style={{flex:1,position:'relative'}}>
          <div style={{position:'absolute',left:11,top:'50%',transform:'translateY(-50%)',color:C.warmL,pointerEvents:'none',lineHeight:0}}>{Ic.search}</div>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search catalog…" style={{width:'100%',boxSizing:'border-box',padding:'9px 12px 9px 34px',borderRadius:10,border:`1.5px solid ${C.beigeD}`,background:'#fff',fontFamily:ff,fontSize:15,color:C.warm,outline:'none'}}/>
        </div>
        <Btn variant="dark" size="sm" onClick={()=>openModal({type:'add-item'})} style={{flexShrink:0}}>{Ic.plus} New Item</Btn>
        <Btn variant="secondary" size="sm" onClick={()=>openModal({type:'import'})} style={{flexShrink:0}}>{Ic.imp} CSV</Btn>
      </div>
      {filtered.length===0?(
        <div style={{textAlign:'center',padding:'50px 0',color:C.warmL,fontFamily:ff}}>
          <div style={{fontSize:36,marginBottom:10}}>🫘</div>
          <div style={{fontWeight:600,fontSize:15}}>{search?'Nothing on the menu':'Your catalog is empty'}</div>
          <div style={{fontSize:13,marginTop:5}}>Tap "New Item" to add your first product</div>
        </div>
      ):filtered.map(it=>{
        const totalQty=data.stock.filter(s=>s.iid===it.id).reduce((a,s)=>a+s.qty,0);
        const locCount=data.stock.filter(s=>s.iid===it.id).length;
        return(
          <div key={it.id} style={{background:'#fff',borderRadius:14,padding:'14px 16px',marginBottom:8,boxShadow:'0 1px 6px rgba(0,0,0,.05)'}}>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',gap:8}}>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontWeight:700,fontSize:15,fontFamily:ff}}>{it.name}</div>
                {it.desc&&<div style={{color:C.warmM,fontSize:12.5,marginTop:3,lineHeight:1.4,fontFamily:ff}}>{it.desc}</div>}
                <div style={{display:'flex',flexWrap:'wrap',gap:6,marginTop:8,alignItems:'center'}}>
                  <Tag color="gold">{it.uom}</Tag>
                  {it.supplier&&user?.role==='admin'&&<Tag color="gold">📦 {it.supplier}</Tag>}
                  <span style={{fontSize:11,color:C.warmL,fontFamily:ff}}>Low at: {it.lowAt}</span>
                </div>
                <div style={{fontSize:12,color:C.warmM,marginTop:6,fontFamily:ff}}>{totalQty} total units · {locCount} location{locCount!==1?'s':''}</div>
              </div>
              <div style={{display:'flex',flexDirection:'column',gap:6,flexShrink:0}}>
                <button onClick={()=>openModal({type:'edit-item',item:it})} style={{padding:'6px 12px',borderRadius:8,border:`1.5px solid ${C.beigeD}`,background:C.beige,color:C.warmM,cursor:'pointer',display:'flex',alignItems:'center',gap:5,fontFamily:ff,fontSize:12.5,fontWeight:500,lineHeight:1}}>{Ic.edit} Edit</button>
                <button onClick={()=>openModal({type:'add-item',prefill:{...it,name:''}})} title="Duplicate this item" style={{padding:'6px 12px',borderRadius:8,border:`1.5px solid ${C.goldL}`,background:C.goldP,color:C.warm,cursor:'pointer',display:'flex',alignItems:'center',gap:5,fontFamily:ff,fontSize:12.5,fontWeight:500,lineHeight:1}}>⎘ Duplicate</button>
                <button onClick={()=>openModal({type:'confirm',title:'Delete Item',message:`Delete "${it.name}" from the catalog? All stock records for this item will also be removed.`,onConfirm:()=>deleteItem(it.id)})} style={{padding:'6px 12px',borderRadius:8,border:`1.5px solid ${C.redL}`,background:C.redL,color:C.red,cursor:'pointer',display:'flex',alignItems:'center',gap:5,fontFamily:ff,fontSize:12.5,fontWeight:500,lineHeight:1}}>{Ic.trash} Delete</button>
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

function LocationsView({data,refresh,openModal}){
  const deleteLoc=async id=>{try{await api.deleteLocation(id);await refresh();}catch(e){alert(e.message);}};
  return(
    <div style={{padding:'14px 16px'}}>
      <div style={{display:'flex',justifyContent:'flex-end',marginBottom:14}}>
        <Btn variant="dark" size="sm" onClick={()=>openModal({type:'add-location'})}>{Ic.plus} Add Location</Btn>
      </div>
      {data.locations.length===0&&<div style={{textAlign:'center',padding:'50px 0',color:C.warmL,fontFamily:ff}}><div style={{fontSize:36,marginBottom:10}}>🏪</div><div style={{fontWeight:600}}>No locations yet</div><div style={{fontSize:13,marginTop:4}}>Add your first café location</div></div>}
      {data.locations.map(loc=>{
        const ls=data.stock.filter(s=>s.lid===loc.id);
        const hasStock=ls.some(s=>s.qty>0);
        const ll=ls.filter(s=>{const it=data.items.find(i=>i.id===s.iid);return it&&s.qty<=it.lowAt;});
        return(
          <div key={loc.id} style={{background:'#fff',borderRadius:14,padding:'14px 16px',marginBottom:8,boxShadow:'0 1px 6px rgba(0,0,0,.05)'}}>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',gap:10}}>
              <div>
                <div style={{fontWeight:700,fontSize:15,fontFamily:ff,display:'flex',alignItems:'center',gap:8,flexWrap:'wrap'}}>{loc.name}{ll.length>0&&<Tag color="red">{ll.length} low</Tag>}</div>
                <div style={{fontSize:12.5,color:C.warmM,marginTop:4,fontFamily:ff}}>{ls.length} items · {ls.reduce((a,s)=>a+s.qty,0)} total units</div>
              </div>
              <button disabled={hasStock} onClick={()=>openModal({type:'confirm',title:'Remove Location',message:`Remove "${loc.name}"? This cannot be undone.`,onConfirm:()=>deleteLoc(loc.id)})} title={hasStock?'Cannot remove location with stock':'Remove location'} style={{padding:'7px 12px',borderRadius:9,border:'none',cursor:hasStock?'not-allowed':'pointer',background:hasStock?C.beige:C.redL,color:hasStock?C.beigeD:C.red,display:'flex',alignItems:'center',gap:5,fontFamily:ff,fontSize:12.5,fontWeight:500,opacity:hasStock?.4:1,lineHeight:1}}>{Ic.trash} {hasStock?'In Use':'Remove'}</button>
            </div>
            {ls.length>0&&(
              <div style={{marginTop:10,paddingTop:10,borderTop:`1px solid ${C.beige}`,display:'flex',flexWrap:'wrap',gap:6}}>
                {ls.map(s=>{const it=data.items.find(i=>i.id===s.iid);if(!it)return null;const low=s.qty<=it.lowAt;return <div key={s.id} style={{fontSize:12,padding:'3px 10px',borderRadius:8,background:low?C.redL:C.beige,color:low?C.red:C.warmM,fontFamily:ff,fontWeight:500}}>{it.name}: {s.qty} {it.uom}</div>;})}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

function ImportView({data,refresh}){
  const [csv,setCsv]=useState('');
  const [preview,setPreview]=useState(null);
  const [err,setErr]=useState('');
  const [success,setSuccess]=useState('');
  const TEMPLATE=`Item Name,UOM,Description,Supplier,Low Threshold,Location,Quantity\nOat Milk,Box,12 packs per box,Oatly,3,Warehouse,10\nOat Milk,Box,12 packs per box,Oatly,3,Athens Shop,4\nEspresso Beans,Bag,1kg bag,Lavazza,2,Warehouse,8`;
  const parse=()=>{
    setErr('');setSuccess('');setPreview(null);
    const lines=csv.trim().split('\n').map(l=>l.trim()).filter(Boolean);
    if(lines.length<2){setErr('Need at least a header row and one data row');return;}
    const headers=lines[0].split(',').map(h=>h.trim().toLowerCase());
    for(const r of['item name','uom','location','quantity'])if(!headers.includes(r)){setErr(`Missing required column: "${r}"`);return;}
    const rows=lines.slice(1).map(line=>{const cells=line.split(',').map(c=>c.trim());const row={};headers.forEach((h,i)=>row[h]=cells[i]||'');return row;});
    const valid=[],bad=[];
    for(const row of rows){if(!row['item name']||!row['uom']||!row['location']||!row['quantity'])bad.push(row);else valid.push(row);}
    if(valid.length===0){setErr('No valid rows found');return;}
    setPreview({valid,bad});
  };
  const doImport=async()=>{
    if(!preview)return;
    const rows=preview.valid.map(row=>({
      itemName:row['item name'],uom:row['uom'],
      desc:row['description']||'',supplier:row['supplier']||'',
      lowAt:parseInt(row['low threshold'])||2,
      locationName:row['location'],qty:parseInt(row['quantity'])||0,
    }));
    try{
      const r=await api.bulkImport(rows);
      await refresh();
      setSuccess(`✓ Imported ${r.imported} record${r.imported!==1?'s':''}!`);
      setCsv('');setPreview(null);
    }catch(e){setErr(e.message);}
  };
  return(
    <div style={{padding:'16px 16px'}}>
      <div style={{background:'#fff',borderRadius:14,padding:'16px',marginBottom:14,boxShadow:'0 1px 6px rgba(0,0,0,.05)'}}>
        <div style={{fontWeight:700,fontSize:14,marginBottom:6,fontFamily:ff}}>CSV Format</div>
        <div style={{fontSize:12.5,color:C.warmM,marginBottom:10,lineHeight:1.5,fontFamily:ff}}>Required columns: <strong>Item Name, UOM, Location, Quantity</strong>. Optional: Description, Supplier, Low Threshold.</div>
        <button onClick={()=>{setCsv(TEMPLATE);setPreview(null);setErr('');setSuccess('');}} style={{background:C.goldP,border:`1px solid ${C.goldL}`,borderRadius:8,padding:'7px 14px',fontSize:12.5,cursor:'pointer',fontFamily:ff,fontWeight:600,color:C.warm}}>Load Example Template</button>
      </div>
      <div style={{marginBottom:10}}>
        <div style={{fontSize:11.5,fontWeight:600,color:C.warmM,marginBottom:6,letterSpacing:.4,textTransform:'uppercase',fontFamily:ff}}>Paste CSV Data</div>
        <textarea value={csv} onChange={e=>setCsv(e.target.value)} placeholder="Paste CSV content here…" style={{width:'100%',boxSizing:'border-box',height:160,padding:'12px 14px',borderRadius:11,border:`1.5px solid ${C.beigeD}`,background:'#fff',fontFamily:'monospace',fontSize:13,color:C.warm,outline:'none',resize:'vertical'}}/>
      </div>
      <ErrBox msg={err}/>
      {success&&<div style={{color:C.green,fontSize:14,fontWeight:600,background:C.greenL,padding:'10px 14px',borderRadius:10,marginBottom:14,fontFamily:ff}}>{success}</div>}
      <Btn onClick={parse} variant="secondary" size="lg" style={{marginBottom:10}}>Preview Import</Btn>
      {preview&&(
        <div style={{background:'#fff',borderRadius:14,padding:'14px',marginTop:8,boxShadow:'0 1px 6px rgba(0,0,0,.05)'}}>
          <div style={{fontWeight:700,fontSize:14,marginBottom:10,fontFamily:ff}}>{preview.valid.length} valid row{preview.valid.length!==1?'s':''}{preview.bad.length>0&&<span style={{color:C.red}}> · {preview.bad.length} skipped</span>}</div>
          <div style={{maxHeight:160,overflowY:'auto',marginBottom:12}}>
            {preview.valid.map((r,i)=><div key={i} style={{fontSize:12.5,padding:'5px 0',borderBottom:`1px solid ${C.beige}`,color:C.warmM,fontFamily:ff}}><strong style={{color:C.warm}}>{r['item name']}</strong> · {r['quantity']} {r['uom']} @ {r['location']}</div>)}
          </div>
          <Btn onClick={doImport} variant="dark" size="lg">Import {preview.valid.length} Records</Btn>
        </div>
      )}
    </div>
  );
}

// ─── LOG SHEET ────────────────────────────────────────────
function LogEntry({e,data}){
  const it=data.items.find(i=>i.id===e.iid);
  const isXfr=e.type==='xfr';
  const fromLoc=isXfr?data.locations.find(l=>l.id===e.fromLid):data.locations.find(l=>l.id===e.lid);
  const toLoc=isXfr?data.locations.find(l=>l.id===e.toLid):null;
  const isUp=!isXfr&&e.delta>0;
  const isDown=!isXfr&&e.delta<0;
  const dot=isXfr?C.gold:isUp?C.green:C.red;
  const icon=isXfr?'⇄':isUp?'▲':'▼';
  return(
    <div style={{display:'flex',gap:12,alignItems:'flex-start',padding:'10px 0',borderBottom:`1px solid ${C.beige}`}}>
      <div style={{width:28,height:28,borderRadius:'50%',background:isXfr?C.goldP:isUp?C.greenL:C.redL,color:dot,display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,flexShrink:0,marginTop:1}}>{icon}</div>
      <div style={{flex:1,minWidth:0}}>
        <div style={{fontWeight:600,fontSize:13.5,fontFamily:ff,color:C.warm,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{it?.name??'Unknown item'}</div>
        {isXfr?(
          <div style={{fontSize:12,color:C.warmM,marginTop:2,fontFamily:ff}}>{fromLoc?.name} → {toLoc?.name} · <span style={{fontWeight:600,color:C.warm}}>{e.qty} {it?.uom}</span></div>
        ):(
          <div style={{fontSize:12,color:C.warmM,marginTop:2,fontFamily:ff}}>{fromLoc?.name} · <span style={{fontWeight:700,color:dot}}>{e.delta>0?'+':''}{e.delta}</span> → {e.toQty} {it?.uom}</div>
        )}
      </div>
      <div style={{flexShrink:0,textAlign:'right'}}>
        <div style={{fontSize:11,color:C.warmL,fontFamily:ff}}>{relTime(e.ts)}</div>
        {e.userName&&<div style={{fontSize:10,color:C.warmL,fontFamily:ff,marginTop:1}}>{e.userName}</div>}
      </div>
    </div>
  );
}

function LogSheet({data,onClose}){
  const [filter,setFilter]=useState('all');
  const log=(data.log||[]).filter(e=>filter==='all'||(filter==='adj'&&e.type==='adj')||(filter==='xfr'&&e.type==='xfr'));
  // Group by day
  const groups=[];
  log.forEach(e=>{
    const label=dayLabel(e.ts);
    const last=groups[groups.length-1];
    if(last&&last.label===label)last.entries.push(e);
    else groups.push({label,entries:[e]});
  });
  return(
    <Sheet title="Activity Log" onClose={onClose}>
      {/* Filter pills */}
      <div style={{display:'flex',gap:8,marginBottom:16}}>
        {[['all','All'],['adj','Adjustments'],['xfr','Transfers']].map(([v,l])=>(
          <button key={v} onClick={()=>setFilter(v)} style={{padding:'6px 14px',borderRadius:20,border:`1.5px solid ${filter===v?C.gold:C.beigeD}`,background:filter===v?C.black:C.beige,color:filter===v?C.gold:C.warmM,fontFamily:ff,fontSize:12.5,fontWeight:filter===v?600:400,cursor:'pointer'}}>{l}</button>
        ))}
      </div>
      {log.length===0?(
        <div style={{textAlign:'center',padding:'40px 0',color:C.warmL,fontFamily:ff}}>
          <div style={{fontSize:36,marginBottom:10}}>📋</div>
          <div style={{fontWeight:600}}>No activity yet</div>
          <div style={{fontSize:13,marginTop:4}}>Actions will appear here as you adjust and transfer stock</div>
        </div>
      ):groups.map(g=>(
        <div key={g.label}>
          <div style={{fontSize:11,fontWeight:700,color:C.warmL,letterSpacing:.8,textTransform:'uppercase',fontFamily:ff,padding:'10px 0 4px'}}>{g.label}</div>
          {g.entries.map(e=><LogEntry key={e.id} e={e} data={data}/>)}
        </div>
      ))}
    </Sheet>
  );
}


// ─── LOGIN SCREEN ─────────────────────────────────────────
function LoginScreen({onLogin}){
  const [pin,setPin]=useState('');
  const [err,setErr]=useState('');
  const [loading,setLoading]=useState(false);
  const submit=async()=>{
    if(pin.length<4){setErr('Enter your 4-digit PIN');return;}
    setLoading(true);setErr('');
    try{const u=await api.login(pin);onLogin(u);}
    catch(e){setErr('Invalid PIN');setPin('');}
    finally{setLoading(false);}
  };
  const press=d=>{if(pin.length<4)setPin(p=>p+d);};
  const del=()=>setPin(p=>p.slice(0,-1));
  return(
    <div style={{background:C.black,minHeight:'100vh',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',gap:0,fontFamily:ff}}>
      <img src={LOGO} alt="Baladi" style={{width:110,marginBottom:6}}/>
      <div style={{fontFamily:fs,fontSize:24,color:C.gold,fontWeight:700,letterSpacing:1,marginBottom:4}}>SirMamun</div>
      <div style={{width:50,height:1.5,background:`linear-gradient(90deg,transparent,${C.gold},transparent)`,marginBottom:28}}/>
      <div style={{background:'#1a1714',borderRadius:18,padding:'28px 32px',width:280,boxShadow:'0 8px 40px rgba(0,0,0,.5)'}}>
        <div style={{textAlign:'center',marginBottom:20}}>
          <div style={{fontSize:12,color:C.warmL,letterSpacing:2,textTransform:'uppercase',marginBottom:12}}>Enter your PIN</div>
          <div style={{display:'flex',justifyContent:'center',gap:12}}>
            {[0,1,2,3].map(i=>(
              <div key={i} style={{width:14,height:14,borderRadius:'50%',background:i<pin.length?C.gold:C.warmM,transition:'background .15s'}}/>
            ))}
          </div>
        </div>
        {err&&<div style={{color:C.red,fontSize:12.5,textAlign:'center',marginBottom:12,background:C.redL,borderRadius:8,padding:'6px 12px'}}>{err}</div>}
        <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:10}}>
          {[1,2,3,4,5,6,7,8,9].map(d=>(
            <button key={d} onClick={()=>press(String(d))} style={{padding:'14px 0',borderRadius:12,background:'#2a2420',color:C.cream,border:'none',cursor:'pointer',fontSize:20,fontWeight:600,fontFamily:fs,transition:'background .1s'}}>{d}</button>
          ))}
          <button onClick={del} style={{padding:'14px 0',borderRadius:12,background:'#2a2420',color:C.warmL,border:'none',cursor:'pointer',fontSize:16,fontFamily:ff}}>⌫</button>
          <button onClick={()=>press('0')} style={{padding:'14px 0',borderRadius:12,background:'#2a2420',color:C.cream,border:'none',cursor:'pointer',fontSize:20,fontWeight:600,fontFamily:fs}}>0</button>
          <button onClick={submit} disabled={loading||pin.length<4} style={{padding:'14px 0',borderRadius:12,background:pin.length>=4?C.gold:'#2a2420',color:pin.length>=4?C.black:C.warmL,border:'none',cursor:pin.length>=4?'pointer':'default',fontSize:15,fontWeight:700,fontFamily:ff,transition:'all .15s'}}>{loading?'…':'✓'}</button>
        </div>
      </div>
    </div>
  );
}

// ─── CONSUME MODAL ────────────────────────────────────────
function ConsumeModal({stockId,data,refresh,onClose,user}){
  const s=data.stock.find(x=>x.id===stockId);
  const it=data.items.find(i=>i.id===s?.iid);
  const lc=data.locations.find(l=>l.id===s?.lid);
  const [amt,setAmt]=useState('1');
  const [err,setErr]=useState('');
  const [done,setDone]=useState(false);
  if(!s||!it)return null;
  const go=async()=>{
    const n=parseInt(amt);
    if(!n||n<=0){setErr('Enter a positive amount');return;}
    if(n>s.qty){setErr(`Only ${s.qty} available`);return;}
    try{await api.consume(s.id,n,{userId:user?.id,userName:user?.name});await refresh();setDone(true);}
    catch(e){setErr(e.message);}
  };
  if(done){
    return(
      <Sheet title="Done" onClose={onClose}>
        <div style={{textAlign:'center',padding:'20px 0'}}>
          <div style={{width:56,height:56,background:C.greenL,borderRadius:'50%',display:'flex',alignItems:'center',justifyContent:'center',margin:'0 auto 14px',color:C.green,fontSize:22,lineHeight:0}}>{Ic.check}</div>
          <div style={{fontWeight:700,fontSize:16,color:C.green,fontFamily:ff}}>Recorded</div>
          <div style={{color:C.warmM,fontSize:13,marginTop:6}}>{amt} {it.uom} of {it.name} taken from {lc?.name}</div>
          <div style={{marginTop:20}}><Btn onClick={onClose} variant="dark" size="lg">Done</Btn></div>
        </div>
      </Sheet>
    );
  }
  return(
    <Sheet title="Record Consumption" onClose={onClose}>
      <div style={{textAlign:'center',marginBottom:20}}>
        <div style={{fontWeight:700,fontSize:15,color:C.warm,fontFamily:ff}}>{it.name}</div>
        <div style={{color:C.warmM,fontSize:13,marginTop:3}}>{lc?.name} · {s.qty} {it.uom} available</div>
      </div>
      <div style={{marginBottom:8}}>
        <div style={{fontSize:11.5,fontWeight:600,color:C.warmM,marginBottom:6,letterSpacing:.4,textTransform:'uppercase',fontFamily:ff}}>How many did you take?</div>
        <input autoFocus type="number" inputMode="numeric" value={amt} onChange={e=>setAmt(e.target.value)} min="1" max={s.qty}
          style={{width:'100%',boxSizing:'border-box',padding:'14px',fontSize:28,fontWeight:700,textAlign:'center',fontFamily:fs,borderRadius:12,border:`2px solid ${C.gold}`,background:'#fff',color:C.warm,outline:'none'}}/>
        <div style={{fontSize:12,color:C.warmL,marginTop:6,textAlign:'center',fontFamily:ff}}>Will leave {Math.max(0,(s.qty-(parseInt(amt)||0)))} {it.uom} in {lc?.name}</div>
      </div>
      <ErrBox msg={err}/>
      <Btn onClick={go} variant="dark" size="lg">☕ Record Consumption</Btn>
    </Sheet>
  );
}

// ─── REORDER VIEW ─────────────────────────────────────────
function ReorderView({data,openModal,user}){
  // Collect all low-stock entries grouped by item
  const lowEntries=data.stock.filter(s=>{const it=data.items.find(i=>i.id===s.iid);return it&&s.qty<=it.lowAt;});
  // Group by item id
  const grouped=data.items.map(it=>{
    const lows=lowEntries.filter(s=>s.iid===it.id);
    return lows.length?{it,lows}:null;
  }).filter(Boolean);
  // Sort: most locations affected first, then alphabetical
  grouped.sort((a,b)=>b.lows.length-a.lows.length||a.it.name.localeCompare(b.it.name));
  const totalShort=grouped.reduce((a,g)=>a+g.lows.reduce((b,s)=>b+Math.max(0,g.it.lowAt-s.qty+1),0),0);

  if(grouped.length===0)return(
    <div style={{padding:'60px 24px',textAlign:'center',color:C.warmL,fontFamily:ff}}>
      <div style={{fontSize:52,marginBottom:14}}>🎉</div>
      <div style={{fontWeight:700,fontSize:18,color:C.green,fontFamily:ff}}>All stocked up!</div>
      <div style={{fontSize:14,marginTop:6,color:C.warmL}}>No items are below their reorder threshold.</div>
    </div>
  );

  return(
    <div style={{padding:'14px 16px'}}>
      {/* Summary banner */}
      <div style={{background:C.black,borderRadius:14,padding:'14px 18px',marginBottom:18,display:'flex',alignItems:'center',gap:14,boxShadow:'0 2px 14px rgba(0,0,0,.18)'}}>
        <div style={{background:C.red,borderRadius:10,width:44,height:44,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2"><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
        </div>
        <div>
          <div style={{fontFamily:fs,fontSize:18,color:C.gold,fontWeight:700,lineHeight:1}}>{grouped.length} item{grouped.length!==1?'s':''} need reordering</div>
          <div style={{fontSize:12,color:C.warmL,marginTop:3,fontFamily:ff}}>{lowEntries.length} location{lowEntries.length!==1?'s':''} affected · ~{totalShort} units short</div>
        </div>
      </div>

      {grouped.map(({it,lows})=>{
        const totalShortItem=lows.reduce((a,s)=>a+Math.max(0,it.lowAt-s.qty+1),0);
        return(
          <div key={it.id} style={{background:'#fff',borderRadius:14,marginBottom:12,overflow:'hidden',boxShadow:'0 1px 8px rgba(0,0,0,.07)',borderLeft:`4px solid ${C.red}`}}>
            {/* Item header */}
            <div style={{padding:'13px 16px 10px',borderBottom:`1px solid ${C.beige}`}}>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',gap:8}}>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontWeight:700,fontSize:15,fontFamily:ff,color:C.warm}}>{it.name}</div>
                  <div style={{display:'flex',flexWrap:'wrap',gap:6,marginTop:5,alignItems:'center'}}>
                    <Tag color="gold">{it.uom}</Tag>
                    {user?.role==='admin'&&(it.supplier?<Tag color="gold">📦 {it.supplier}</Tag>:<span style={{fontSize:11,color:C.beigeD,fontFamily:ff,fontStyle:'italic'}}>No supplier set</span>)}
                    <span style={{fontSize:11,color:C.warmL,fontFamily:ff}}>threshold: {it.lowAt}</span>
                  </div>
                </div>
                <div style={{textAlign:'right',flexShrink:0}}>
                  <div style={{background:C.redL,color:C.red,borderRadius:10,padding:'4px 10px',fontSize:12,fontWeight:600,fontFamily:ff,whiteSpace:'nowrap'}}>~{totalShortItem} short</div>
                </div>
              </div>
            </div>
            {/* Per-location rows */}
            {lows.map(s=>{
              const lc=data.locations.find(l=>l.id===s.lid);
              const short=Math.max(0,it.lowAt-s.qty+1);
              return(
                <div key={s.id} style={{padding:'10px 16px',display:'flex',alignItems:'center',gap:10,borderBottom:`1px solid ${C.beige}`}}>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontWeight:500,fontSize:13,fontFamily:ff,color:C.warmM}}>{lc?.name}</div>
                    <div style={{fontSize:11.5,color:C.warmL,marginTop:1,fontFamily:ff}}>
                      <span style={{color:C.red,fontWeight:600}}>{s.qty}</span> {it.uom} · needs {short} more to reach threshold
                    </div>
                  </div>
                  <div style={{display:'flex',gap:6,flexShrink:0}}>
                    <button onClick={()=>openModal({type:'transfer',prefillItemId:it.id,prefillFromId:''})} style={{padding:'6px 10px',borderRadius:8,border:`1.5px solid ${C.beigeD}`,background:C.beige,color:C.warmM,cursor:'pointer',display:'flex',alignItems:'center',gap:4,fontFamily:ff,fontSize:12,fontWeight:500,lineHeight:1}}>{Ic.trans} Transfer</button>
                    <button onClick={()=>openModal({type:'adjust',stockId:s.id})} style={{padding:'6px 10px',borderRadius:8,border:`1.5px solid ${C.gold}`,background:C.goldP,color:C.warm,cursor:'pointer',fontFamily:ff,fontSize:12,fontWeight:600,lineHeight:1}}>+ Adjust</button>
                  </div>
                </div>
              );
            })}
            {/* Item footer: transfer from best-stocked */}
            {(()=>{
              const best=data.stock.filter(s=>s.iid===it.id&&!lows.find(l=>l.id===s.id)&&s.qty>it.lowAt).sort((a,b)=>b.qty-a.qty)[0];
              if(!best)return null;
              const bestLoc=data.locations.find(l=>l.id===best.lid);
              return(
                <div style={{padding:'8px 16px',background:C.greenL,display:'flex',alignItems:'center',justifyContent:'space-between',gap:8}}>
                  <div style={{fontSize:12,color:C.green,fontFamily:ff,fontWeight:500}}>
                    💡 {bestLoc?.name} has {best.qty} — consider transferring
                  </div>
                  <button onClick={()=>openModal({type:'transfer',prefillItemId:it.id,prefillFromId:best.lid})} style={{padding:'5px 10px',borderRadius:7,border:'none',background:C.green,color:'#fff',cursor:'pointer',fontFamily:ff,fontSize:11.5,fontWeight:600,flexShrink:0,lineHeight:1}}>Transfer →</button>
                </div>
              );
            })()}
          </div>
        );
      })}
    </div>
  );
}


// ─── SETTINGS VIEW ────────────────────────────────────────
function SettingsView({user}){
  const [users,setUsers]=useState([]);
  const [loading,setLoading]=useState(true);
  const [modal,setModal]=useState(null); // {type:'add'} or {type:'edit',u}
  const [name,setName]=useState('');
  const [pin,setPin]=useState('');
  const [role,setRole]=useState('staff');
  const [err,setErr]=useState('');

  const load=async()=>{try{setUsers(await api.listUsers());}finally{setLoading(false);}};
  useEffect(()=>{load();},[]);

  const openAdd=()=>{setName('');setPin('');setRole('staff');setErr('');setModal({type:'add'});};
  const openEdit=u=>{setName(u.name);setPin('');setRole(u.role);setErr('');setModal({type:'edit',u});};

  const save=async()=>{
    if(!name.trim()){setErr('Name required');return;}
    if(modal.type==='add'&&pin.length!==4){setErr('PIN must be 4 digits');return;}
    if(modal.type==='edit'&&pin&&pin.length!==4){setErr('New PIN must be 4 digits');return;}
    try{
      if(modal.type==='add')await api.createUser(name.trim(),pin,role);
      else await api.updateUser(modal.u.id,{name:name.trim(),role,...(pin?{pin}:{})});
      await load();setModal(null);
    }catch(e){setErr(e.message);}
  };

  const del=async u=>{if(!window.confirm(`Remove ${u.name}?`))return;await api.deleteUser(u.id);await load();};

  if(user?.role!=='admin')return(
    <div style={{padding:'60px 24px',textAlign:'center',color:C.warmL,fontFamily:ff}}>
      <div style={{fontSize:40,marginBottom:12}}>🔒</div>
      <div style={{fontWeight:600,fontSize:16,color:C.warm}}>Admin only</div>
    </div>
  );

  return(
    <div style={{padding:'14px 16px'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div style={{fontFamily:fs,fontSize:18,color:C.warm,fontWeight:700}}>Staff PINs</div>
        <Btn variant="dark" size="sm" onClick={openAdd}>{Ic.plus} Add Staff</Btn>
      </div>
      {loading?<div style={{color:C.warmL,fontFamily:ff,textAlign:'center',padding:30}}>Loading…</div>:users.map(u=>(
        <div key={u.id} style={{background:'#fff',borderRadius:14,padding:'13px 16px',marginBottom:8,display:'flex',alignItems:'center',gap:10,boxShadow:'0 1px 6px rgba(0,0,0,.05)'}}>
          <div style={{flex:1}}>
            <div style={{fontWeight:600,fontSize:14,fontFamily:ff,color:C.warm}}>{u.name}</div>
            <div style={{fontSize:12,color:C.warmL,marginTop:2,fontFamily:ff,textTransform:'capitalize'}}>{u.role}</div>
          </div>
          <button onClick={()=>openEdit(u)} style={{padding:'6px 12px',borderRadius:8,border:`1.5px solid ${C.beigeD}`,background:C.beige,color:C.warmM,cursor:'pointer',fontFamily:ff,fontSize:12.5,fontWeight:500}}>{Ic.edit} Edit</button>
          {u.id!==user.id&&<button onClick={()=>del(u)} style={{padding:'6px 12px',borderRadius:8,border:`1.5px solid ${C.redL}`,background:C.redL,color:C.red,cursor:'pointer',fontFamily:ff,fontSize:12.5,fontWeight:500}}>{Ic.trash}</button>}
        </div>
      ))}
      {modal&&(
        <Sheet title={modal.type==='add'?'New Staff':'Edit Staff'} onClose={()=>setModal(null)}>
          <Inp label="Name" value={name} onChange={setName} placeholder="e.g. Maria" required/>
          <Inp label={modal.type==='add'?'4-Digit PIN':'New PIN (leave blank to keep)'}
            value={pin} onChange={v=>setPin(v.replace(/\D/g,'').slice(0,4))}
            placeholder="••••" type="text" inputMode="numeric"
            note={modal.type==='edit'?'Leave blank to keep current PIN':''}/>
          <div style={{marginBottom:16}}>
            <div style={{fontSize:11.5,fontWeight:600,color:C.warmM,marginBottom:6,letterSpacing:.4,textTransform:'uppercase',fontFamily:ff}}>Role</div>
            <div style={{display:'flex',gap:8}}>
              {['staff','admin'].map(r=>(
                <button key={r} onClick={()=>setRole(r)} style={{flex:1,padding:'10px',borderRadius:10,border:`1.5px solid ${role===r?C.gold:C.beigeD}`,background:role===r?C.black:C.beige,color:role===r?C.gold:C.warmM,cursor:'pointer',fontFamily:ff,fontSize:13,fontWeight:role===r?700:400,textTransform:'capitalize'}}>{r}</button>
              ))}
            </div>
          </div>
          <ErrBox msg={err}/>
          <Btn onClick={save} variant="dark" size="lg">Save</Btn>
        </Sheet>
      )}
    </div>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────
export default function App(){
  const [data,setData]=useState(null);
  const [tab,setTab]=useState('dashboard');
  const [modal,setModal]=useState(null);
  const [err,setErr]=useState(null);
  const [user,setUser]=useState(()=>{try{const u=sessionStorage.getItem('sm_user');return u?JSON.parse(u):null;}catch{return null;}});
  const logout=()=>{sessionStorage.removeItem('sm_user');setUser(null);};

  const refresh=useCallback(async()=>{
    try{const d=await api.fetchAll();setData(d);}
    catch(e){setErr('Could not reach server. Check your connection.');}
  },[]);

  useEffect(()=>{
    refresh();
    const link=document.createElement('link');
    link.rel='stylesheet';
    link.href='https://fonts.googleapis.com/css2?family=Playfair+Display:wght@500;700&family=DM+Sans:opsz,wght@9..40,300;9..40,400;9..40,500;9..40,600;9..40,700&display=swap';
    document.head.appendChild(link);
    // Poll every 30s so all devices stay in sync
    const id=setInterval(refresh,30000);
    return()=>clearInterval(id);
  },[refresh]);

  const openModal=useCallback(m=>setModal(m),[]);
  const closeModal=useCallback(()=>setModal(null),[]);
  if(!user)return <LoginScreen onLogin={u=>{sessionStorage.setItem('sm_user',JSON.stringify(u));setUser(u);}}/>;
  if(!data)return(
    <div style={{background:C.black,height:'100vh',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',gap:0}}>
      <img src={LOGO} alt="Baladi" style={{width:140,opacity:.95,marginBottom:4}}/>
      <div style={{fontFamily:fs,fontSize:26,color:C.gold,fontWeight:700,letterSpacing:1,marginBottom:6}}>SirMamun</div>
      <div style={{width:60,height:1.5,background:`linear-gradient(90deg,transparent,${C.gold},transparent)`,borderRadius:1,marginBottom:14}}/>
      {err
        ?<div style={{fontFamily:ff,fontSize:13,color:C.red,letterSpacing:.5,textAlign:'center',padding:'0 32px'}}>{err}<br/><button onClick={refresh} style={{marginTop:12,padding:'8px 20px',borderRadius:8,background:C.gold,color:C.black,border:'none',fontFamily:ff,fontWeight:600,cursor:'pointer',fontSize:13}}>Retry</button></div>
        :<div style={{fontFamily:ff,fontSize:12,color:C.warmL,letterSpacing:2,textTransform:'uppercase'}}>Loading…</div>
      }
    </div>
  );
  const low=data.stock.filter(s=>{const it=data.items.find(i=>i.id===s.iid);return it&&s.qty<=it.lowAt;});
  const settingsIcon=<svg width="21" height="21" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 00.33 1.82l.06.06a2 2 0 010 2.83 2 2 0 01-2.83 0l-.06-.06a1.65 1.65 0 00-1.82-.33 1.65 1.65 0 00-1 1.51V21a2 2 0 01-4 0v-.09A1.65 1.65 0 009 19.4a1.65 1.65 0 00-1.82.33l-.06.06a2 2 0 01-2.83-2.83l.06-.06A1.65 1.65 0 004.68 15a1.65 1.65 0 00-1.51-1H3a2 2 0 010-4h.09A1.65 1.65 0 004.6 9a1.65 1.65 0 00-.33-1.82l-.06-.06a2 2 0 012.83-2.83l.06.06A1.65 1.65 0 009 4.68a1.65 1.65 0 001-1.51V3a2 2 0 014 0v.09a1.65 1.65 0 001 1.51 1.65 1.65 0 001.82-.33l.06-.06a2 2 0 012.83 2.83l-.06.06A1.65 1.65 0 0019.4 9a1.65 1.65 0 001.51 1H21a2 2 0 010 4h-.09a1.65 1.65 0 00-1.51 1z"/></svg>;
  const TABS=[{key:'dashboard',label:'Dashboard',icon:Ic.dash},{key:'inventory',label:'Inventory',icon:Ic.inv},{key:'catalog',label:'Catalog',icon:Ic.cat},{key:'reorder',label:'Reorder',icon:Ic.reorder},{key:'locations',label:'Locations',icon:Ic.loc},...(user?.role==='admin'?[{key:'settings',label:'Settings',icon:settingsIcon}]:[])];
  const tabTitles={dashboard:'Dashboard',inventory:'Inventory',catalog:'Item Catalog',reorder:'Reorder List',locations:'Locations',settings:'Settings'};
  return(
    <div style={{background:C.cream,minHeight:'100vh',fontFamily:ff,color:C.warm,maxWidth:480,margin:'0 auto',paddingBottom:74,position:'relative'}}>
      {/* Logo watermark */}
      <div style={{position:'fixed',top:'50%',left:'50%',transform:'translate(-50%,-50%)',width:320,maxWidth:'85vw',pointerEvents:'none',zIndex:0,opacity:.045}}>
        <img src={LOGO} alt="" style={{width:'100%',filter:'sepia(1) saturate(3) hue-rotate(5deg)'}}/>
      </div>
      <header style={{background:C.black,padding:'0 16px',height:56,display:'flex',alignItems:'center',justifyContent:'space-between',position:'sticky',top:0,zIndex:100,boxShadow:'0 2px 14px rgba(0,0,0,.32)'}}>
        <div style={{display:'flex',alignItems:'center',gap:8}}>
          <img src={LOGO} alt="Baladi" style={{height:32,width:'auto',objectFit:'contain'}}/>
          <div>
            <div style={{fontFamily:fs,fontSize:17,color:C.gold,fontWeight:700,letterSpacing:.5,lineHeight:1}}>SirMamun</div>
            <div style={{height:1,background:`linear-gradient(90deg,${C.gold},transparent)`,marginTop:2}}/>
          </div>
          <div style={{width:1,height:20,background:C.gold,opacity:.25,borderRadius:1,marginLeft:2}}/>
          <span style={{fontSize:10.5,color:C.warmL,letterSpacing:1.5,textTransform:'uppercase',fontFamily:ff}}>{tabTitles[tab]}</span>
        </div>
        <div style={{display:'flex',alignItems:'center',gap:8,flexShrink:0}}>
          {low.length>0&&<div onClick={()=>setTab('reorder')} style={{background:C.red,color:'#fff',borderRadius:20,padding:'4px 10px',fontSize:12,fontWeight:600,display:'flex',alignItems:'center',gap:4,cursor:'pointer',lineHeight:0}}><span style={{lineHeight:0}}>{Ic.warn}</span><span style={{lineHeight:1}}> {low.length}</span></div>}
          {user&&<button onClick={logout} title="Log out" style={{background:'none',border:`1px solid ${C.warmM}`,borderRadius:8,color:C.warmL,fontFamily:'var(--ff,sans-serif)',fontSize:11,padding:'4px 8px',cursor:'pointer',flexShrink:0}}>{user.name} ✕</button>}
        </div>
      </header>
      <div style={{position:'relative',zIndex:1}}>
      {tab==='dashboard'&&<DashboardView data={data} openModal={openModal}/>}
      {tab==='inventory'&&<InventoryView data={data} refresh={refresh} openModal={openModal} user={user}/>}
      {tab==='catalog'&&<CatalogView data={data} refresh={refresh} openModal={openModal} user={user}/>}
      {tab==='reorder'&&<ReorderView data={data} openModal={openModal} user={user}/>}
      {tab==='locations'&&<LocationsView data={data} refresh={refresh} openModal={openModal}/>}
      {tab==='settings'&&<SettingsView user={user}/>}
      </div>
      <nav style={{position:'fixed',bottom:0,left:'50%',transform:'translateX(-50%)',width:'100%',maxWidth:480,background:C.black,display:'flex',borderTop:'1px solid #1E1A15',paddingBottom:'env(safe-area-inset-bottom,0px)',zIndex:100}}>
        {TABS.map(({key,label,icon})=>(
          <button key={key} onClick={()=>setTab(key)} style={{flex:1,padding:'10px 0 12px',background:'none',border:'none',display:'flex',flexDirection:'column',alignItems:'center',gap:3,cursor:'pointer',color:tab===key?C.gold:C.warmM,transition:'color .2s',fontFamily:ff}}>
            <div style={{lineHeight:0,position:'relative'}}>
              {icon}
              {key==='dashboard'&&low.length>0&&<div style={{position:'absolute',top:-2,right:-4,width:7,height:7,background:C.red,borderRadius:'50%',border:'1.5px solid '+C.black}}/>}
              {key==='reorder'&&low.length>0&&<div style={{position:'absolute',top:-2,right:-4,width:7,height:7,background:C.red,borderRadius:'50%',border:'1.5px solid '+C.black}}/>}
            </div>
            <span style={{fontSize:9.5,fontWeight:tab===key?600:400,letterSpacing:.3}}>{label}</span>
          </button>
        ))}
      </nav>
      {modal?.type==='adjust'&&<AdjustModal stockId={modal.stockId} data={data} refresh={refresh} onClose={closeModal} user={user}/>}
      {modal?.type==='consume'&&<ConsumeModal stockId={modal.stockId} data={data} refresh={refresh} onClose={closeModal} user={user}/>}
      {modal?.type==='transfer'&&<TransferModal prefillItemId={modal.prefillItemId} prefillFromId={modal.prefillFromId} data={data} refresh={refresh} onClose={closeModal} user={user}/>}
      {modal?.type==='add-item'&&<AddEditItemModal editItem={null} prefill={modal.prefill} data={data} refresh={refresh} onClose={closeModal} user={user}/>}
    </div>
  );
}
